from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Get the raw data from the request body
    data = request.get_data(as_text=True)

    if not data:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent execution of arbitrary Python code (CWE-502)
        parsed_data = yaml.safe_load(data)

        # Ensure the parsed result is a type that can be serialized to JSON
        if not isinstance(parsed_data, (dict, list, str, int, float, bool)) and parsed_data is not None:
            return jsonify({"error": "YAML content must be a standard data type"}), 400

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
